#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int isVowel(char c){return c=='a'||c=='e'||c=='i'||c=='o'||c=='u';}
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,K; scanf("%d %d",&N,&K);
        char s[1000005]; scanf("%s",s);
        int pos[1000005]; int vcnt=0;
        for(int i=0;i<N;i++) if(isVowel(s[i])) pos[vcnt++]=i+1; // 1‑based
        long long ans=1;
        for(int i=K-1;i+K<vcnt;i+=K){
            long long diff = pos[i+K] - pos[i];
            ans = (ans * diff) % MOD;
        }
        printf("%lld\n",ans);
    }
    return 0;
}

